const item = $input.first().json;
const exp = item.body.expense || {};
const owner_id = item.ids.owner_id;
const operator_id = item.ids.operator;

const doc = {
    _id: 'exp_' + Date.now(),
    owner_id: owner_id,
    merchant: exp.merchant,
    date: exp.date || new Date().toISOString().split('T')[0],
