    vat_rate: parseFloat(exp.vat_rate || 22),
    account_code: exp.account_code || '626.00202',
    deductibility: parseFloat(exp.deductibility ?? 75),
    operator_id: operator_id,
    created_at: new Date().toISOString()
};

return [{ json: doc }];

const sop = $('Find SOP Recipe').first().json;
const recipe = sop.materials || [];
const stockLogs = $input.all().map(i => i.json);
const request = $('Action Router').first().json;
const qtyToProduce = parseFloat(request.body.qty || 1);
const lotIdToAssign = request.body.lot_id;
const owner_id = request.ids.owner_id;
const operator_id = request.ids.operator;

// 1. Calculate stock balances per product and lot (FIFO sorted by expiry)
const balances = {};
stockLogs.forEach(log => {
    const pId = log.product_id;
    if (!pId) return;
    const lId = log.lot_id || 'N/A';
    const key = pId + '_' + lId;
    if (!balances[key]) {
        balances[key] = {
            product_id: pId,
            lot_id: lId,
            expiry_date: log.expiry_date || 'N/A',
            balance: 0
        };
    }
    const qty = parseFloat(log.quantity || 0);
    if (log.direction === 'IN' || log.type === 'PURCHASE' || log.type === 'PRODUCTION_OUTPUT') {
        balances[key].balance += qty;
    } else {
        balances[key].balance -= qty;
    }
});

// Convert to array and filter out empty balances, sort by expiry ascending (FIFO)
const lotList = Object.values(balances)
    .filter(b => b.balance > 0)
    .sort((a, b) => {
        if (a.expiry_date === 'N/A') return 1;
        if (b.expiry_date === 'N/A') return -1;
        return new Date(a.expiry_date) - new Date(b.expiry_date);
    });

const movements = [];

// 2. Loop over materials in recipe and deduct using FIFO lots
recipe.forEach(material => {
    const reqQty = parseFloat(material.qty || 0) * qtyToProduce;
    let remaining = reqQty;

    // Find matching lots for this material
    const matchingLots = lotList.filter(l => l.product_id === material.product_id);

    for (const lot of matchingLots) {
        if (remaining <= 0) break;
        const consume = Math.min(lot.balance, remaining);

        movements.push({
            owner_id: owner_id,
            product_id: lot.product_id,
            name: material.name,
            lot_id: lot.lot_id,
            expiry_date: lot.expiry_date,
            quantity: consume,
            direction: 'OUT',
            type: 'PRODUCTION_CONSUME',
            related_doc_id: 'prod_' + lotIdToAssign,
            operator_id: operator_id,
            created_at: new Date().toISOString()
        });

        remaining -= consume;
        lot.balance -= consume;
    }

    // If we couldn't fulfill completely from stock, log the remainder from N/A lot
    if (remaining > 0) {
        movements.push({
            owner_id: owner_id,
            product_id: material.product_id,
            name: material.name,
            lot_id: 'UNTRACKED',
            expiry_date: 'N/A',
            quantity: remaining,
            direction: 'OUT',
            type: 'PRODUCTION_CONSUME',
            related_doc_id: 'prod_' + lotIdToAssign,
            operator_id: operator_id,
            created_at: new Date().toISOString()
        });
    }
});

// 3. Add the produced semilavorato lot entry (IN)
movements.push({
    owner_id: owner_id,
    product_id: request.body.sop_id, // SOP ID is the Digital Twin ID of the semilavorato
    name: sop.blueprint_name || sop.name || 'Semilavorato Prodotto',
    lot_id: lotIdToAssign,
    expiry_date: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0], // Default 30 days expiry
    quantity: qtyToProduce,
    direction: 'IN',
    type: 'PRODUCTION_OUTPUT',
    related_doc_id: 'prod_' + lotIdToAssign,
    operator_id: operator_id,
    created_at: new Date().toISOString()
});

return movements.map(m => ({ json: m }));

return [{ json: {
    sops: $('Aggregate SOPs').first().json.sops,
    stockLogs: $input.all().map(i => i.json)
} }];

const sops = $json.sops || [];
const stockLogs = $json.stockLogs || [];

// Group logs to get current total balance per product
const productStock = {};
stockLogs.forEach(log => {
    const pId = log.product_id;
    if (!pId) return;
    if (productStock[pId] === undefined) productStock[pId] = 0;
    const qty = parseFloat(log.quantity || 0);
    if (log.direction === 'IN' || log.type === 'PURCHASE' || log.type === 'PRODUCTION_OUTPUT') {
        productStock[pId] += qty;
    } else {
        productStock[pId] -= qty;
    }
});

// Update each material in each SOP with its current available stock
sops.forEach(sop => {
    if (sop.materials && Array.isArray(sop.materials)) {
        sop.materials.forEach(m => {
            m.available_stock = productStock[m.product_id] || 0;
        });
    }
});

return [{ json: { sops } }];

const invoices = $('Aggregate Invoices').first().json.invoices || [];
const expenses = $input.all().map(i => i.json);

// Group all line items and expenses by account_code
const totals = {};

invoices.forEach(item => {
    if (item.lines && Array.isArray(item.lines)) {
        item.lines.forEach(line => {
            const code = line.account_code || '631.01000';
            if (totals[code] === undefined) totals[code] = 0;
            const amt = parseFloat(line.unit_price || 0) * parseFloat(line.qty || 1);
            totals[code] += amt;
        });
    }
});

expenses.forEach(item => {
    if (item.total_amount !== undefined && item.merchant) {
        const code = item.account_code || '626.00202';
        if (totals[code] === undefined) totals[code] = 0;
        totals[code] += parseFloat(item.total_amount || 0);
    }
});

return [{
    json: {
        actual_expenses: totals
    }
}];

const item = $input.first().json;
const xmlText = item.body.xml_content || '';

// Regex patterns to extract lines from Italian Electronic Invoice XML
const lines = [];
const lineRegex = /<DettaglioLinee>([\s\S]*?)<\/DettaglioLinee>/g;
let match;
let idx = 1;

while ((match = lineRegex.exec(xmlText)) !== null) {
    const block = match[1];
    const descMatch = block.match(/<Descrizione>([\s\S]*?)<\/Descrizione>/);
    const qtyMatch = block.match(/<Quantita>([\s\S]*?)<\/Quantita>/);
    const priceMatch = block.match(/<PrezzoUnitario>([\s\S]*?)<\/PrezzoUnitario>/);
    const vatMatch = block.match(/<AliquotaIVA>([\s\S]*?)<\/AliquotaIVA>/);
    const skuMatch = block.match(/<CodiceArticolo>[\s\S]*?<CodiceValore>([\s\S]*?)<\/CodiceValore>[\s\S]*?<\/CodiceArticolo>/);

    if (descMatch) {
        lines.push({
            line_id: idx++,
            name: descMatch[1].trim(),
            sku: skuMatch ? skuMatch[1].trim() : '',
            qty: qtyMatch ? parseFloat(qtyMatch[1]) : 1,
            price: priceMatch ? parseFloat(priceMatch[1]) : 0,
            tax: vatMatch ? parseFloat(vatMatch[1]) : 22,
            productId: '',
            lot: '',
            expiry: '',
            account_code: '631.01000',
            deductibility: 100
        });
    }
}

return [{
    json: {
        extractedLines: lines
    }
}];

const products = $input.all().map(i => i.json);
const lines = $('Parse XML Invoice Deterministic').first().json.extractedLines || [];

// Helper for lexical overlaps (Bigrams n-grams overlap)
function calculateNgramOverlap(s1, s2) {
    const getBigrams = str => {
        const bigrams = new Set();
        const s = str.toLowerCase().replace(/[^a-z0-9]/g, '');
        for (let i = 0; i < s.length - 1; i++) bigrams.add(s.slice(i, i + 2));
        return bigrams;
    };
    const b1 = getBigrams(s1);
    const b2 = getBigrams(s2);
    if (b1.size === 0 || b2.size === 0) return 0;
    let intersection = 0;
    b1.forEach(b => { if (b2.has(b)) intersection++; });
    return intersection / Math.max(b1.size, b2.size);
}

// Perform lexical matching
const matchedItems = lines.map(line => {
    let bestMatch = null;
    let bestScore = 0;

    // Simple Brand Detector from description
    const getBrand = name => {
        const brands = ["3m", "kerr", "coltene", "kuraray", "tokuyama", "henry schein", "schein", "krugg", "septodont", "dentsply", "zhermack", "kulzer"];
        const n = name.toLowerCase();
        return brands.find(b => n.includes(b)) || "";
    };

    const lineBrand = getBrand(line.name);

    products.forEach(p => {
        const prodName = p.name.replace('[PRO] ', '');
        const prodBrand = p.brand || getBrand(prodName);

        // Brand Mismatch Hard Filter
        if (lineBrand && prodBrand && lineBrand !== prodBrand) {
            return; // Score remains 0
        }

        let score = 0;

        // 1. SKU Exact Match (Weight: 50)
        if (line.sku && p.sku && line.sku.toLowerCase() === p.sku.toLowerCase()) {
            score += 50;
        }

        // 2. Brand Match (Weight: 15)
        if (lineBrand && prodBrand && lineBrand === prodBrand) {
            score += 15;
        }

        // 3. Measure match (e.g. A2, 3g, 4ml) (Weight: 10)
        const measureRegex = /\b(\d+g|\d+ml|a[1-4]|b[1-4])\b/gi;
        const lineMeasures = line.name.match(measureRegex) || [];
        const prodMeasures = prodName.match(measureRegex) || [];
        if (lineMeasures.length > 0 && prodMeasures.length > 0 && lineMeasures[0].toLowerCase() === prodMeasures[0].toLowerCase()) {
            score += 10;
        }

        // 4. Title N-gram overlap (Weight: 8)
        const overlap = calculateNgramOverlap(line.name, prodName);
        score += overlap * 8;

        if (score > bestScore) {
            bestScore = score;
            bestMatch = p;
        }
    });

    const mapped = { ...line };
    if (bestMatch && bestScore >= 15) {
        mapped.productId = bestMatch._id;
        mapped.name = bestMatch.name.replace('[PRO] ', '');
        mapped.account_code = bestMatch.account_code || '631.01000';
        mapped.deductibility = bestMatch.deductibility ?? 100;
        mapped.confidence = bestScore >= 40 ? 'HIGH' : 'MEDIUM';
    } else {
        mapped.productId = '';
        mapped.confidence = 'PENDING_REVIEW';
    }

    mapped.match_score = bestScore;
    return mapped;
});

return [{
    json: {
        items: matchedItems
    }
}];

