const item = $input.first().json;
const geminiResponse = item.text || item.content || "";
let result = {};
try {
    const cleanJson = geminiResponse.replace(/```json/g, "").replace(/```/g, "").trim();
    result = JSON.parse(cleanJson);
} catch(e) {
    console.error("Gemini Parse Error:", e);
}
return [{ json: result }];

